    // 使用 shared_ptr 管理内存生命周期，确保在多线程环境下引用计数正确
    auto data = std::make_shared<std::vector<int>>(100);

    // 通过值传递 (capture by value) 拷贝 shared_ptr，增加引用计数
    // 即使主线程函数结束，只要线程还在运行，data 指向的内存就不会被释放
    std::thread t([data]() {
        std::this_thread::sleep_for(std::chrono::seconds(1));
        if (!data->empty()) {
            (*data)[0] = 10;
        }
    });

    // 修复生命周期风险：严禁在存在后台线程访问内存时使用 detach()
    // 必须使用 join() 等待线程执行完毕，确保内存访问安全
    if (t.joinable()) {
        t.join();
    }
}
