type Telemetry struct {
	ID    string
	Value float64
}

type TelemetryService struct {
	taskChan    chan []Telemetry
	workerCount int
	maxRetries  int
	wg          sync.WaitGroup
}

func NewTelemetryService(workerCount int, bufferSize int, maxRetries int) *TelemetryService {
	return &TelemetryService{
		taskChan:    make(chan []Telemetry, bufferSize),
		workerCount: workerCount,
		maxRetries:  maxRetries,
	}
}

func (s *TelemetryService) Start(ctx context.Context) {
	for i := 0; i < s.workerCount; i++ {
		s.wg.Add(1)
		go s.worker(ctx, i)
	}
}

func (s *TelemetryService) Stop() {
	close(s.taskChan)
	s.wg.Wait()
}

func (s *TelemetryService) HandleBatch(records []Telemetry) {
	if len(records) == 0 {
		return
	}
	s.taskChan <- records
}

func (s *TelemetryService) worker(ctx context.Context, id int) {
	defer s.wg.Done()
	for {
		select {
		case <-ctx.Done():
			return
		case batch, ok := <-s.taskChan:
			if !ok {
				return
			}
			s.processWithRetry(batch)
		}
	}
}

func (s *TelemetryService) processWithRetry(batch []Telemetry) {
	var err error
	for attempt := 0; attempt <= s.maxRetries; attempt++ {
		err = s.writeToStorage(batch)
		if err == nil {
			return
		}

		log.Printf("[Worker] Attempt %d failed: %v", attempt+1, err)
		if attempt < s.maxRetries {
			time.Sleep(time.Millisecond * 100 * time.Duration(attempt+1)) // Exponential backoff
		}
	}
	log.Printf("[Error] Failed to write batch after %d retries: %v", s.maxRetries, err)
}

